SELECT id, date, user_id, user_name, voucher, tip
FROM sf_voucher_tip
WHERE date = #{date}

SELECT id, date, user_id, user_name, voucher, tip
FROM sf_voucher_tip
WHERE date = #{yearMonth}

SELECT id, date, user_id, user_name, voucher, tip
FROM sf_voucher_tip
WHERE date BETWEEN #{startDate} AND #{endDate}
